import React, { useEffect, useState } from "react";
import { Link } from 'react-router-dom';
import API from '../api/axios';
import "../style.css";

function HomePage() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <p style={{textAlign: 'center', padding: '2rem'}}>Loading posts...</p>;

  return (
    <div className="home-wrapper">
      {/* Hero Section */}
      <section className="hero-section">
        <h1>Welcome to TheFolio</h1>
        <p>A community blog where members share ideas, stories, and inspiration.</p>
      </section>

      {/* Preview Cards */}
      <section className="preview-section">
        <div className="preview-cards">
          <div className="preview-card">
            <h3>📖 About</h3>
            <p>Learn about my coding journey and what inspires me.</p>
            <Link to="/about" className="card-link">Read More →</Link>
          </div>
          <div className="preview-card">
            <h3>💬 Contact</h3>
            <p>Get in touch and explore useful resources.</p>
            <Link to="/contact" className="card-link">Get in Touch →</Link>
          </div>
          <div className="preview-card">
            <h3>👥 Join</h3>
            <p>Sign up and become part of our community.</p>
            <Link to="/register" className="card-link">Register Now →</Link>
          </div>
        </div>
      </section>

      {/* Latest Posts */}
      <section className="posts-section">
        <h2>Latest Posts</h2>
        {posts.length === 0 ? (
          <p style={{textAlign: 'center', color: '#666', padding: '2rem'}}>No posts yet. Be the first to write one!</p>
        ) : (
          <div className="posts-grid">
            {posts.map(post => (
              <Link to={`/posts/${post._id}`} key={post._id} className="post-card-link">
                <div className="post-card">
                  {post.image && (
                    <div className="post-image">
                      <img src={`http://localhost:5000/uploads/${post.image}`} alt={post.title} />
                    </div>
                  )}
                  <div className="post-details">
                    <h3>{post.title}</h3>
                    <p>{post.body.substring(0, 80)}...</p>
                    <small>By {post.author?.name} • {new Date(post.createdAt).toLocaleDateString()}</small>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </section>
    </div>
  );
}

export default HomePage;
